import{_ as o,o as a,c as t,a2 as s}from"./chunks/framework.BYlK8ftn.js";const u=JSON.parse('{"title":"Objective & win/lose loop (world conquest)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/objective-loop.md","filePath":"guide/objective-loop.md","lastUpdated":1782035748000}'),n={name:"guide/objective-loop.md"};function r(d,e,i,c,l,h){return a(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="objective-win-lose-loop-world-conquest" tabindex="-1">Objective &amp; win/lose loop (world conquest) <a class="header-anchor" href="#objective-win-lose-loop-world-conquest" aria-label="Permalink to &quot;Objective &amp; win/lose loop (world conquest)&quot;">​</a></h1><p>The objective loop is what turns the forest sandbox into a <em>game</em>: a player who clicks <strong>New Game</strong> is given a goal — <strong>conquer the worlds</strong> — surfaced on the HUD, and the run ends in an explicit <strong>win</strong> or <strong>lose</strong> screen with a <strong>Restart</strong> button. Score (kills + loot) is tracked throughout.</p><p>The campaign model (caravan <strong>quotas per world</strong>, sequential unlock, win when every available world is conquered) is specified in <a href="./../decisions/0005-win-goal-conquest">ADR 0005</a>. This guide documents the implementation.</p><h2 id="the-run-flow" tabindex="-1">The run flow <a class="header-anchor" href="#the-run-flow" aria-label="Permalink to &quot;The run flow&quot;">​</a></h2><p>App/run flow is the <a href="./state-management"><code>appSlice</code></a> phase machine. The objective loop adds two end-of-run phases:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>menu → playing ⇄ paused</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ├── every available world conquered ──▶ won  ──▶ (Restart → playing | Quit → menu)</span></span>
<span class="line"><span>          └── player HP reaches 0 ────────────────▶ lost ──▶ (Restart → playing | Quit → menu)</span></span></code></pre></div><ul><li><code>winGame</code> / <code>loseGame</code> only transition <strong>from <code>playing</code></strong> — an already finished run never re-triggers, and a finished run cannot be paused.</li><li>On <code>won</code>/<code>lost</code> the live zone scene is <strong>unmounted</strong>: <code>GameCanvas</code> keeps a scene only while <code>playing</code>/<code>paused</code>, so the win/lose overlay sits above the menu engine scene. Restart bumps the run and boots a <strong>fresh</strong> zone scene from scratch (the capsule, raided caravans, and corpses all reset with it).</li></ul><h2 id="world-conquest-—-quotas-unlock-win" tabindex="-1">World conquest — quotas, unlock, win <a class="header-anchor" href="#world-conquest-—-quotas-unlock-win" aria-label="Permalink to &quot;World conquest — quotas, unlock, win&quot;">​</a></h2><p>Conquest is <strong>data-driven</strong> and reads three pieces of world data, all co-located with <a href="./world-map"><code>ZONES</code></a> in <code>src/game/world/zones.ts</code>:</p><table tabindex="0"><thead><tr><th>Data</th><th>Meaning</th></tr></thead><tbody><tr><td><code>ZONE_CARAVAN_QUOTAS</code></td><td>Caravans to raid to <strong>conquer</strong> a world — forest 3, human-lands 5, empire 6, mountains 8.</td></tr><tr><td><code>ZONE_CONQUEST_ORDER</code></td><td>Campaign sequence; a world unlocks once the <strong>previous</strong> one is conquered.</td></tr><tr><td><code>ZONES[id].status</code></td><td><code>available</code> (has a playable scene) vs <code>locked</code> (empire/mountains, no scene yet).</td></tr></tbody></table><p>The win condition reads <code>ZONES.status</code> — there is <strong>no hardcoded world count</strong>, so the campaign auto-extends to four worlds the moment empire and mountains flip to <code>available</code> and ship their scenes.</p><h2 id="the-win-lose-conquest-state-machine" tabindex="-1">The win/lose / conquest state machine <a class="header-anchor" href="#the-win-lose-conquest-state-machine" aria-label="Permalink to &quot;The win/lose / conquest state machine&quot;">​</a></h2><p>The <em>decisions</em> — is a world conquered, which worlds are unlocked, and is the run still going, won, or lost? — are pure functions with no Redux/React/Babylon dependency, so they are exhaustively unit-testable (<code>src/game/objective/objectiveMachine.ts</code>):</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isZoneConquered</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(zoneId, raidedByZone, quotas)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// → boolean</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">unlockedZoneIds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(conquestOrder, raidedByZone, quotas)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// → unlocked prefix</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evaluateOutcome</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ raidedByZone, quotas, availableZoneIds, playerDead })</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // → &#39;playing&#39; | &#39;won&#39; | &#39;lost&#39;</span></span></code></pre></div><ul><li><strong>Conquered</strong> — caravans raided in a zone reach its quota; an unknown zone (no quota) is never conquered.</li><li><strong>Unlocked</strong> — walking <code>ZONE_CONQUEST_ORDER</code>, the first world is always unlocked and each next world unlocks once the prior is conquered. This is progression gating only; <code>status</code> (does the world have a scene?) is intersected separately by the world map.</li><li><strong>Win</strong> = every <code>available</code> world is conquered. An empty available set can never win (guards a misconfigured zone table from declaring an instant victory). <strong>Death takes priority over victory</strong>, keeping <code>evaluateOutcome</code> total.</li></ul><p>The App layer feeds these live state each frame (via the effects in <code>App.tsx</code>) and drives the <code>appSlice</code> phase from the result.</p><h2 id="objective-score-state" tabindex="-1">Objective &amp; score state <a class="header-anchor" href="#objective-score-state" aria-label="Permalink to &quot;Objective &amp; score state&quot;">​</a></h2><p>Per-run progress lives in <a href="./state-management"><code>gameSlice</code></a>:</p><table tabindex="0"><thead><tr><th>Field</th><th>Meaning</th></tr></thead><tbody><tr><td><code>caravansRaidedByZone</code></td><td>Caravans raided this run <strong>per zone</strong> — the conquest progress (<code>Record&lt;zoneId, number&gt;</code>).</td></tr><tr><td><code>caravansRaided</code></td><td>Flat total across all zones — informational / score path only.</td></tr><tr><td><code>kills</code></td><td>Soldiers defeated this run.</td></tr><tr><td><code>score</code></td><td>Running score shown in the HUD (see below).</td></tr></tbody></table><p><strong>Score</strong> accumulates as the run plays: <code>KILL_SCORE</code> (10) per soldier defeated plus the loot points (item count) of each caravan raided. Raids <strong>beyond</strong> a world&#39;s quota still count and still score — pure farming.</p><p>Actions: <code>recordKill</code>, <code>raidCaravan({ zoneId, lootPoints })</code>, <code>restoreRunProgress(byZone)</code>, <code>resetRun</code>. <code>raidCaravan</code> increments the <strong>current zone&#39;s</strong> count (the dispatcher passes <code>playerSlice.zoneId</code>) and the flat total. Both the New-Game flow (after the faction picker confirms) and the win/lose <strong>Restart</strong> run the same full reset (<code>resetRun</code> + zone/HP/injuries/inventory) before entering play — Restart reuses the current faction rather than re-prompting.</p><p>A continued save <strong>restores conquest progress</strong>: <code>restoreRunProgress</code> rebuilds <code>caravansRaidedByZone</code> from the persisted map (recomputing the flat total so the two stay consistent); score and kills are not persisted and start fresh. See <a href="./save-system">save system</a> (save <strong>v5</strong> added the per-zone map).</p><h2 id="how-progress-is-fed-from-the-scene" tabindex="-1">How progress is fed from the scene <a class="header-anchor" href="#how-progress-is-fed-from-the-scene" aria-label="Permalink to &quot;How progress is fed from the scene&quot;">​</a></h2><p>The forest scene stays decoupled from the store and reports events through callbacks that <code>GameCanvas</code> adapts into dispatches:</p><ul><li><strong>Caravan raided</strong> — defeating a caravan fires <code>onCaravanLooted(drop)</code> (see <a href="./caravans">caravans</a>). <code>GameCanvas</code> dispatches <code>pickUpLoot</code> per stack <strong>and</strong> <code>raidCaravan({ zoneId, lootPoints })</code> (reading the player&#39;s current zone), which advances that zone&#39;s conquest progress and folds the haul into the loot score.</li><li><strong>Soldier killed</strong> — <code>reapDeadSoldiers</code> fires <code>onEnemyKilled</code> once per fresh death (see <a href="./enemy-ai">enemy AI</a> / <a href="./corpses">corpses</a>); <code>GameCanvas</code> dispatches <code>recordKill</code>.</li></ul><h2 id="hud" tabindex="-1">HUD <a class="header-anchor" href="#hud" aria-label="Permalink to &quot;HUD&quot;">​</a></h2><p>While playing/paused the HUD shows the objective counter — <strong>Worlds conquered <code>X / N</code></strong> plus the current world&#39;s caravan progress (e.g. <code>Forest 1/3</code>) — and the running <code>Score</code>. Fresh runs from the faction picker also show the <a href="./onboarding">onboarding intro</a> overlay before play begins, which names the first world and its quota. The win and lose screens reuse the menu/pause overlay chrome with win- and lose-tinted accents; the win summary reports how many worlds were conquered.</p><h2 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h2><ul><li><code>src/game/objective/objectiveMachine.test.ts</code> — the conquest/win/lose machine: <code>isZoneConquered</code>, <code>unlockedZoneIds</code>, and <code>evaluateOutcome</code> (playing/partial/won/lost, death-priority, and empty-available edges).</li><li><code>src/store/gameSlice.test.ts</code> — per-zone raid reducers, <code>restoreRunProgress</code>, and selectors.</li><li><code>src/store/appSlice.test.ts</code> — <code>won</code>/<code>lost</code> transitions and guards.</li><li><code>src/game/save/schema.test.ts</code> — v4→v5 migration fills <code>caravansRaidedByZone</code> with no data loss.</li><li><code>src/app/App.test.tsx</code> — HUD objective/score, win and lose screens, and the end-to-end <strong>Restart from win → fresh game</strong> flow.</li></ul>`,29)])])}const g=o(n,[["render",r]]);export{u as __pageData,g as default};
